from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
from flask_login import LoginManager, UserMixin, login_user, login_required, logout_user, current_user

app = Flask(__name__)

app.config['SECRET_KEY'] = 'secret-key'
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:////database.db'

db = SQLAlchemy(app)

login_manager = LoginManager()
login_manager.login_view = 'login'
login_manager.init_app(app)

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(15), unique=True)
    password = db.Column(db.String(80))
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_code = db.Column(db.Integer)

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        user = User.query.filter_by(username=request.json.get('username')).first()
        if user and check_password_hash(user.password, request.json.get('password')):
            login_user(user)
            if user.mfa_enabled:
                return jsonify({'msg': 'Enter OTP'}), 401
            return jsonify({'msg': 'Logged in'}), 200
        return jsonify({'msg': 'Invalid username or password'}), 401
    return jsonify({'msg': 'Login Page'}), 200

@app.route('/otp', methods=['POST'])
@login_required
def otp():
    if request.method == 'POST':
        if current_user.mfa_code == request.json.get('otp'):
            return jsonify({'msg': 'Logged in'}), 200
        return jsonify({'msg': 'Invalid OTP'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    if request.method == 'POST':
        user = User.query.filter_by(username=request.json.get('username')).first()
        if user and check_password_hash(user.password, request.json.get('password')):
            login_user(user)
            return jsonify({'msg': 'Logged in'}), 200
        return jsonify({'msg': 'Invalid username or password'}), 401

@app.route("/logout")
@login_required
def logout():
    logout_user()
    return jsonify({'msg': 'Logged out'}), 200